import { useState } from "react"
import searchFriend from "../../api/search/friend";

export default function FriendSearch(){
    const [ email, setEmail] = useState();
    const [ result, setResult ] = useState();
    

    return(
        <div>
            {userInfo ? 
                <div>
                    <div>
                        <div>
                            <input type="search" 
                                onChange={(value) => setEmail(value.target.value)}
                                onKeyDown={async (e) => {
                                    if(e.key === 'Enter'){
                                        const data = await searchFriend({email});
                                        setResult(data.data);
                                    }
                                }}/>
                        </div>
                        <div>
                            <button>검색</button>
                        </div>
                    </div>
                    <div>
                        {result ? 
                        <div>

                        </div>
                        : 
                        <div>
                            <h3>친구를 검색해보세요!</h3>
                        </div>}
                    </div>
                </div>
                : null}
        </div>
    )
}
